'use client';

import React, { useEffect } from 'react';
import { Box } from '@mui/material';

const b64_scripts = "";
const b64_css = "";
const b64_html = "";

function decodeBase64(str: string) {
  try {
    return decodeURIComponent(
      atob(str)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
  } catch (e) {
    return atob(str);
  }
}

export default function ImageToPdf() {
  useEffect(() => {
    const runScript = () => {
      try {
        const scriptText = decodeBase64(b64_scripts);
        const scriptFunc = new Function(scriptText);
        scriptFunc();
      } catch (err) {
        console.error("Error executing script for ImageToPdf:", err);
      }
    };
    
    const timer = setTimeout(runScript, 50);
    return () => clearTimeout(timer);
  }, []);

  return (
    <Box className="native-tool-container" sx={{ width: '100%', minHeight: '80vh' }}>
      <style dangerouslySetInnerHTML={{ __html: decodeBase64(b64_css) }} />
      <div dangerouslySetInnerHTML={{ __html: decodeBase64(b64_html) }} />
    </Box>
  );
}
